    LinearLayout root; byte[] key; String childIp=""; TextView log; TextView childPairCodeView; TextView childCountdownView; ImageView childQrView; Handler handler=new Handler(Looper.getMainLooper()); BroadcastReceiver br; int parentVolume=50; Thread discoveryListenThread; boolean unlockedThisRun=false; boolean authPromptLaunched=false; boolean childPairingDetailsVisible=false;

    public void onCreate(Bundle b){super.onCreate(b);LanguageManager.applySavedLocale(this); migrateUiDefaults(); getWindow().setSoftInputMode(WindowManager.LayoutParams.SOFT_INPUT_ADJUST_RESIZE); ensureParentNotificationChannels(); if(Build.VERSION.SDK_INT>=33)requestPermissions(new String[]{Manifest.permission.POST_NOTIFICATIONS},7); ensureIds(); checkForUpdatesInBackground(); handleDeepLinkOrStart();}
    void migrateUiDefaults(){SharedPreferences p=getSharedPreferences("p",0);if(!p.getBoolean("darkUiDefault2918",false)){p.edit().putString("themeMode","dark").putBoolean("darkUiDefault2918",true).apply();}}
    void checkForUpdatesInBackground(){try{UpdateChecker.checkLatestRelease(this,DEFAULT_REPO,null);}catch(Exception ignored){}}
    void handleDeepLinkOrStart(){Intent launch=getIntent();if(launch!=null&&"unlock_request".equals(launch.getStringExtra("open"))){unlockedThisRun=true;showUnlockRequestScreen();return;}Uri u=launch!=null?launch.getData():null;if(u!=null&&"family-link".equals(u.getScheme())&&"pair".equals(u.getHost())){String code=u.getQueryParameter("code");getSharedPreferences("p",0).edit().putString("pendingPairCode",code==null?"":code).apply();showParentConnection(code==null?"":code);return;}showStartOrSaved();}
    void ensureIds(){SharedPreferences p=getSharedPreferences("p",0);if(p.getString("localDeviceId","").length()==0)p.edit().putString("localDeviceId",UUID.randomUUID().toString()).putString("parentName","Parent Control").apply();}
    void showStartOrSaved(){SavedConnection c=new SavedConnection(this);String role=c.role();if(c.hasParentConnection()){childIp=c.childIp();key=c.parentKeyBytesOrNull();if(!unlockedThisRun)showParentAppLock();else showConnectedParent(true);}else if(role.equals("child")){showChild();}else showStart();}
    @Override public void onBackPressed(){if(sidePanel!=null&&sidePanel.isShowing()){sidePanel.dismiss();return;}if(isHomeScreen()){long now=System.currentTimeMillis();if(now-lastDashboardBackMs<1600){moveTaskToBack(true);}else{lastDashboardBackMs=now;toast("Press Back again to leave Parental-Link");}return;}goDashboardFromTopBar();}
    boolean isHomeScreen(){return "dashboard".equals(currentScreen)||"child".equals(currentScreen)||"start".equals(currentScreen);}
    void goDashboardFromTopBar(){SharedPreferences p=getSharedPreferences("p",0);SavedConnection c=new SavedConnection(this);if(c.hasParentConnection()&&unlockedThisRun){showConnectedParent(false);return;}if("child".equals(p.getString("role",""))){showChild();return;}if(c.hasParentConnection()){showParentAppLock();return;}showStartOrSaved();}
    protected void onDestroy(){try{if(br!=null)unregisterReceiver(br);}catch(Exception ignored){}super.onDestroy();}
    protected void onActivityResult(int requestCode,int resultCode,Intent data){if(requestCode==AUTH_REQUEST){if(resultCode==RESULT_OK){unlockParentApp("biometrics");}else toast("Unlock cancelled");return;}IntentResult result=IntentIntegrator.parseActivityResult(requestCode,resultCode,data);if(result!=null){if(result.getContents()!=null)handlePairQr(result.getContents().trim());else toast("QR scan cancelled");return;}super.onActivityResult(requestCode,resultCode,data);}

    void addLog(String msg){AppLog.add(this,msg);}
