    void base(String title){handler.removeCallbacksAndMessages(null);root=UiFactory.attachRoot(this);SharedPreferences p=getSharedPreferences("p",0);UiFactory.addTopBar(this,root,p,v->showUserMenu(),v->goDashboardFromTopBar());attachDashboardSwipe(root);if(title!=null&&title.length()>0)root.addView(tv(title,22));log=tv("",14);}
    void fixedBase(String title){handler.removeCallbacksAndMessages(null);root=UiFactory.attachFixedRoot(this);SharedPreferences p=getSharedPreferences("p",0);UiFactory.addTopBar(this,root,p,v->showUserMenu(),v->goDashboardFromTopBar());attachDashboardSwipe(root);if(title!=null&&title.length()>0)root.addView(tv(title,22));log=tv("",14);}

    void showParentAppLock(){lockBase();SharedPreferences p=getSharedPreferences("p",0);String savedPin=p.getString("appPin","");long lockUntil=p.getLong("pinLockUntil",0);long now=System.currentTimeMillis();root.addView(tv("Parental-Link",26));root.addView(tv("Unlock parent dashboard",18));if(lockUntil>now){long sec=Math.max(1,(lockUntil-now+999)/1000);root.addView(tv("Too many wrong attempts. Try again in "+sec+" seconds.",16));handler.postDelayed(()->showParentAppLock(),Math.min(lockUntil-now,60000));return;}if(!authPromptLaunched&&canUseDeviceCredential()){authPromptLaunched=true;handler.postDelayed(()->launchDeviceCredential(),250);}if(savedPin.length()==0){showCreateParentPin(p);return;}TextView dots=tv("",32);dots.setGravity(Gravity.CENTER);root.addView(dots);final StringBuilder entered=new StringBuilder();GridLayout pad=new GridLayout(this);pad.setColumnCount(3);pad.setPadding(0,24,0,16);for(String label:new String[]{"1","2","3","4","5","6","7","8","9","⌫","0","Bio"}){Button b=btn(label);pad.addView(b,new ViewGroup.LayoutParams(getResources().getDisplayMetrics().widthPixels/3-28,130));b.setOnClickListener(v->{String t=((Button)v).getText().toString();if(t.equals("⌫")){if(entered.length()>0)entered.deleteCharAt(entered.length()-1);}else if(t.equals("Bio")){launchDeviceCredential();}else{if(entered.length()<6)entered.append(t);}StringBuilder stars=new StringBuilder();for(int i=0;i<entered.length();i++)stars.append("• ");dots.setText(stars.toString());if(entered.length()>=4&&entered.toString().equals(savedPin)){unlockParentApp("PIN");}else if(entered.length()==6&&!entered.toString().equals(savedPin)){registerWrongPinAttempt();}});}root.addView(pad);root.addView(tv("Use the number pad. Press Bio if the biometric prompt was closed.",13));}
    void lockBase(){handler.removeCallbacksAndMessages(null);root=UiFactory.attachRoot(this);root.setPadding(36,72,36,36);log=tv("",14);}    
    boolean canUseDeviceCredential(){KeyguardManager km=(KeyguardManager)getSystemService(KEYGUARD_SERVICE);return Build.VERSION.SDK_INT>=21&&km!=null&&km.isDeviceSecure();}
    void launchDeviceCredential(){try{KeyguardManager km=(KeyguardManager)getSystemService(KEYGUARD_SERVICE);if(Build.VERSION.SDK_INT>=21&&km!=null&&km.isDeviceSecure()){Intent i=km.createConfirmDeviceCredentialIntent("Parental-Link","Unlock parent dashboard");if(i!=null)startActivityForResult(i,AUTH_REQUEST);}}catch(Exception e){toast("Biometric unlock unavailable");}}
    void unlockParentApp(String method){SharedPreferences.Editor e=getSharedPreferences("p",0).edit();e.putInt("pinFailCount",0).putLong("pinLockUntil",0).apply();unlockedThisRun=true;addLog("Parent app unlocked by "+method);showConnectedParent(false);}    
    void registerWrongPinAttempt(){SharedPreferences p=getSharedPreferences("p",0);int fails=p.getInt("pinFailCount",0)+1;long[] delays={5000L,30000L,60000L,900000L,3600000L};long d=delays[Math.min(fails-1,delays.length-1)];p.edit().putInt("pinFailCount",fails).putLong("pinLockUntil",System.currentTimeMillis()+d).apply();addLog("Wrong parent PIN attempt");toast("Wrong PIN");showParentAppLock();}
    void showCreateParentPin(SharedPreferences p){root.addView(tv("Create a 4–6 digit parent PIN fallback.",15));EditText p1=new EditText(this);p1.setHint("New PIN");p1.setInputType(InputType.TYPE_CLASS_NUMBER|InputType.TYPE_NUMBER_VARIATION_PASSWORD);p1.setFilters(new InputFilter[]{new InputFilter.LengthFilter(6)});root.addView(p1);EditText p2=new EditText(this);p2.setHint("Repeat PIN");p2.setInputType(InputType.TYPE_CLASS_NUMBER|InputType.TYPE_NUMBER_VARIATION_PASSWORD);p2.setFilters(new InputFilter[]{new InputFilter.LengthFilter(6)});root.addView(p2);Button save=btn("Save PIN and unlock");root.addView(save);if(canUseDeviceCredential()){Button bio=btn("Unlock with biometrics");root.addView(bio);bio.setOnClickListener(v->launchDeviceCredential());}save.setOnClickListener(v->{String a=p1.getText().toString().trim(),b=p2.getText().toString().trim();if(a.length()<4||a.length()>6){toast("Use 4 to 6 digits");return;}if(!a.equals(b)){toast("PINs do not match");return;}p.edit().putString("appPin",a).putInt("pinFailCount",0).putLong("pinLockUntil",0).apply();unlockParentApp("new PIN");});}

    void showStart(){base("");currentScreen="start";root.addView(tv("Parental-Link",28));root.addView(tv("Choose how this device will be used.",16));Button parent=btn("Parent device");Button child=btn("Child device");root.addView(parent);root.addView(child);parent.setOnClickListener(v->{getSharedPreferences("p",0).edit().putString("role","parent").apply();showParentConnection("");});child.setOnClickListener(v->{getSharedPreferences("p",0).edit().putString("role","child").apply();showChild();});}

