    String shortConnectionLine(){SharedPreferences p=getSharedPreferences("p",0);if(p.getBoolean("pairingMismatch",false))return "Pairing issue";long last=p.getLong("lastStatusMs",0);if(last<=0)return "No status";long age=(System.currentTimeMillis()-last)/60000;if(age<2)return "Online";if(age<30)return age+"m ago";return "Stale";}
    int connectionColor(){SharedPreferences p=getSharedPreferences("p",0);if(p.getBoolean("pairingMismatch",false))return UiFactory.red();long last=p.getLong("lastStatusMs",0);if(last<=0)return Color.rgb(120,130,145);long age=(System.currentTimeMillis()-last)/60000;if(age<2)return UiFactory.green();if(age<30)return Color.rgb(245,160,45);return UiFactory.red();}
