        addParentTile(grid,timeout?"■":"⏳",timeout?"Stop":"Timeout",timeout?UiFactory.green():UiFactory.blue(),v->{if(getSharedPreferences("p",0).getBoolean("parentTimeoutActive",false))cmdWithCallback("stop_timeout","dashboard",resp->{setLocalTimeoutState(false);out(resp);showConnectedParent(false);},err->{out(err);});else showTimeoutDialog();});
