    LinearLayout deviceStatusCard(SharedPreferences p){LinearLayout card=dashboardCard();LinearLayout top=new LinearLayout(this);top.setOrientation(LinearLayout.HORIZONTAL);top.setGravity(Gravity.CENTER_VERTICAL);TextView avatar=tv("👦",34);avatar.setGravity(Gravity.CENTER);android.graphics.drawable.GradientDrawable av=new android.graphics.drawable.GradientDrawable();av.setShape(android.graphics.drawable.GradientDrawable.OVAL);av.setColor(UiFactory.isDark(this)?Color.rgb(37,54,76):Color.rgb(212,230,255));avatar.setBackground(av);top.addView(avatar,new LinearLayout.LayoutParams(UiFactory.dp(this,70),UiFactory.dp(this,70)));LinearLayout info=new LinearLayout(this);info.setOrientation(LinearLayout.VERTICAL);TextView name=tv(new DeviceProfile(this).childNickname(),22);name.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);info.addView(name);info.addView(UiFactory.mutedText(this,connectionLine(),13));String app=currentAppDisplay();info.addView(UiFactory.mutedText(this,"Battery "+p.getInt("remoteBattery",78)+"%  •  Wi‑Fi connected",13));info.addView(UiFactory.mutedText(this,"Current app: "+app,13));String state=p.getBoolean("parentTimeoutActive",false)?"Timeout active":(p.getBoolean("parentChildDisabled",false)?"Device disabled":"Ready");info.addView(tv(state,15));top.addView(info,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));card.addView(top);if(p.getBoolean("pairingMismatch",false)){Button repair=btn("Repair pairing");card.addView(repair);repair.setOnClickListener(v->showRepairPairingScreen());}return card;}
    LinearLayout requestCard(SharedPreferences p){LinearLayout card=dashboardCard();boolean pending=p.getBoolean("childUnlockRequestPending",false);card.setBackground(UiFactory.rounded(this,pending?(UiFactory.isDark(this)?Color.rgb(48,22,25):Color.rgb(255,238,238)):UiFactory.panel(this),16));LinearLayout head=new LinearLayout(this);head.setOrientation(LinearLayout.HORIZONTAL);head.setGravity(Gravity.CENTER_VERTICAL);TextView title=tv(pending?"Request":"Requests",15);title.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);title.setTextColor(pending?UiFactory.red():UiFactory.textColor(this));title.setPadding(0,0,0,0);head.addView(title,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));card.addView(head);if(pending){TextView msg=UiFactory.mutedText(this,"Unlock requested • "+p.getString("childUnlockRequestReason","limitation"),12);msg.setPadding(0,0,0,UiFactory.dp(this,4));card.addView(msg);LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);Button allow=UiFactory.primaryButton(this,"Allow");Button snooze=btn("Snooze");row.addView(allow,new LinearLayout.LayoutParams(0,UiFactory.dp(this,38),1));row.addView(snooze,new LinearLayout.LayoutParams(0,UiFactory.dp(this,38),1));card.addView(row);allow.setOnClickListener(v->cmdWithCallback("enable_use","parent_dashboard",resp->{clearUnlockRequestLocal();setLocalLockState(false);setLocalTimeoutState(false);toast("Device enabled");showConnectedParent(false);},err->{toast("Enable failed");out(err);}));snooze.setOnClickListener(v->cmdWithCallback("snooze_ask_parent","15",resp->{clearUnlockRequestLocal();toast("Snoozed");showConnectedParent(false);},err->{toast("Snooze failed");out(err);}));}else{TextView empty=UiFactory.mutedText(this,"Requests will be visible here.",12);empty.setPadding(0,0,0,0);card.addView(empty);if(!parentAlertsAllowed()){TextView warn=UiFactory.mutedText(this,"Parent alert notifications are disabled.",12);warn.setTextColor(UiFactory.red());card.addView(warn);warn.setOnClickListener(v->openAppNotificationSettings());}}return card;}
    LinearLayout activityCard(SharedPreferences p){LinearLayout card=dashboardCard();LinearLayout head=new LinearLayout(this);head.setOrientation(LinearLayout.HORIZONTAL);head.setGravity(Gravity.CENTER_VERTICAL);TextView t=tv("Activity",15);t.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);t.setPadding(0,0,0,0);head.addView(t,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));TextView view=tv("View all",12);view.setTextColor(UiFactory.blue());view.setGravity(Gravity.RIGHT);view.setOnClickListener(v->showCommandHistoryScreen());head.addView(view,new LinearLayout.LayoutParams(UiFactory.dp(this,70),UiFactory.dp(this,30)));card.addView(head);String body=latestActivityLines().replaceFirst("^Activity\\n?","");if(body.trim().length()==0)body="No recent activity";int shown=0;for(String line:body.split("\\n")){if(line.trim().length()==0)continue;TextView row=UiFactory.mutedText(this,line.trim(),12);row.setSingleLine(true);row.setPadding(0,UiFactory.dp(this,1),0,UiFactory.dp(this,1));card.addView(row);if(++shown>=3)break;}return card;}
        void setLocalLockState(boolean disabled){getSharedPreferences("p",0).edit().putBoolean("parentChildDisabled",disabled).apply();}
    void setLocalTimeoutState(boolean active){getSharedPreferences("p",0).edit().putBoolean("parentTimeoutActive",active).apply();}
    String customSlotLabel(int slot){String action=getSharedPreferences("p",0).getString("quickSlot"+slot,"");return action.length()==0?"+\nChoose\naction":shortMenuLabel(action).replace(" ","\n");}
    void runCustomSlot(int slot){String action=getSharedPreferences("p",0).getString("quickSlot"+slot,"");if(action.length()==0)showInterfaceSettingsScreen();else handleMenuAction(action);} 
    String connectionLine(){SharedPreferences p=getSharedPreferences("p",0);if(p.getBoolean("pairingMismatch",false))return "Possible pairing mismatch";long last=p.getLong("lastStatusMs",0);if(last<=0)return "Connected locally • no child status yet";long age=(System.currentTimeMillis()-last)/60000;return age<2?"Online":"Last sync: "+age+" min ago";}
    String latestActivityLines(){SharedPreferences prefs=getSharedPreferences("p",0);StringBuilder sb=new StringBuilder("Activity\n");int n=0;String cmd=prefs.getString("commandHistory","");java.util.HashSet<String> seen=new java.util.HashSet<>();if(cmd.trim().length()>0){for(String row:cmd.split("\\n")){String[] c=row.split("\\|",-1);if(c.length<4)continue;String id=c.length>1?c[1]:"";if(id.length()>0&&!seen.add(id))continue;String command=c[2];String status=c[3];String details=c.length>4?c[4]:"";String value=c.length>5?c[5]:"";sb.append(compactActivityLine(command,status,details,value)).append("\n");if(++n>=3)break;}}String raw=prefs.getString("logs","");if(raw.trim().length()>0){for(String line:raw.split("\\n")){if(line.trim().length()==0)continue;if(line.contains("[Commands/"))continue;sb.append(AppLog.lineSummary(line)).append("\n");if(++n>=5)break;}}if(n==0)sb.append("No recent activity");return sb.toString().trim();}
    String compactActivityLine(String command,String status,String details,String value){if("quick_chat".equals(command)){String title=quickMessageTitle(details,value);return "💬 "+title+" — "+status;}return prettyCommandName(command)+" — "+status;}
    String quickMessageTitle(String details,String value){String d=details==null?"":details.trim();if(d.length()>0&&!d.equalsIgnoreCase("Delivered")&&!d.equalsIgnoreCase("Sending"))return d;String v=value==null?"":value;String[] parts=v.split("\\|",5);if(parts.length>=3)return (parts[1]+" "+parts[2]).trim();return "Quick message";}
    String prettyCommandName(String command){if(command==null)return "Command";String c=command.trim();if(c.equals("volume"))return "Media volume";if(c.equals("disable_use"))return "Disable use";if(c.equals("enable_use"))return "Enable device";if(c.equals("lock_timeout"))return "Timeout";if(c.equals("stop_timeout"))return "Stop timeout";if(c.equals("remove_all_limitations"))return "Remove limits";if(c.equals("quick_chat"))return "Quick message";if(c.equals("ping"))return "Ring device";return c.replace('_',' ');}
    void refreshParentDashboard(){cmdWithCallback("usage","today",resp->{TextView dummy=tv("",1);updateUsageViews(resp,dummy,null);try{startService(new Intent(this,ParentMonitorService.class));}catch(Exception ignored){}showConnectedParent(false);},err->{out(err);try{startService(new Intent(this,ParentMonitorService.class));}catch(Exception ignored){}});}
    void clearUnlockRequestLocal(){getSharedPreferences("p",0).edit().remove("childUnlockRequestPending").remove("childUnlockRequestReason").remove("childUnlockRequestAt").remove("childUnlockSnoozeUntil").remove("lastParentUnlockAlertAt").apply();}
    void showUnlockRequestScreen(){base("Unlock request");currentScreen="unlock_request";SharedPreferences p=getSharedPreferences("p",0);root.addView(tv("The child asked the parent to unlock the device.",17));root.addView(tv("Reason: "+p.getString("childUnlockRequestReason","limitation"),15));Button allow=btn("Allow / enable device now");Button snooze=btn("Snooze Ask Parent for 15 minutes");Button stop=btn("Stop timeout only");Button back=btn("Back to dashboard");root.addView(allow);root.addView(snooze);root.addView(stop);root.addView(back);allow.setOnClickListener(v->cmdWithCallback("enable_use","unlock_request",resp->{clearUnlockRequestLocal();toast("Device enabled");showConnectedParent(false);},err->{toast("Enable failed");out(err);}));snooze.setOnClickListener(v->cmdWithCallback("snooze_ask_parent","15",resp->{clearUnlockRequestLocal();toast("Snoozed");showConnectedParent(false);},err->{toast("Snooze failed");out(err);}));stop.setOnClickListener(v->cmdWithCallback("stop_timeout","unlock_request",resp->{clearUnlockRequestLocal();toast("Timeout stopped");showConnectedParent(false);},err->{toast("Stop timeout failed");out(err);}));back.setOnClickListener(v->showConnectedParent(false));root.addView(log);}
    void showVolumeScreen(){base("Media volume");currentScreen="media_volume";SharedPreferences p=getSharedPreferences("p",0);final int[] percent={p.getInt("parentVolume",50)};TextView label=tv("Media volume limit: "+percent[0]+"%",20);root.addView(label);SeekBar bar=new SeekBar(this);bar.setMax(100);bar.setProgress(percent[0]);root.addView(bar,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.WRAP_CONTENT));bar.setOnSeekBarChangeListener(new SeekBar.OnSeekBarChangeListener(){public void onProgressChanged(SeekBar s,int progress,boolean fromUser){percent[0]=progress;label.setText("Media volume limit: "+progress+"%");}public void onStartTrackingTouch(SeekBar s){}public void onStopTrackingTouch(SeekBar s){getSharedPreferences("p",0).edit().putInt("parentVolume",percent[0]).apply();cmd("volume","media|"+percent[0]+"|set");}});LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);Button down=btn("−");Button set=btn("Set");Button up=btn("+");row.addView(down,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));row.addView(set,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));row.addView(up,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));root.addView(row);down.setOnClickListener(v->{int n=Math.max(0,percent[0]-5);bar.setProgress(n);});up.setOnClickListener(v->{int n=Math.min(100,percent[0]+5);bar.setProgress(n);});set.setOnClickListener(v->{getSharedPreferences("p",0).edit().putInt("parentVolume",percent[0]).apply();cmd("volume","media|"+percent[0]+"|set");});Button mute=btn("Mute media");Button unmute=btn("Unmute media");Button back=btn("Back");root.addView(mute);root.addView(unmute);root.addView(back);mute.setOnClickListener(v->cmd("volume","media|0|mute"));unmute.setOnClickListener(v->cmd("volume","media|"+percent[0]+"|unmute"));back.setOnClickListener(v->showConnectedParent(false));root.addView(log);}

    void showTimeoutDialog(){final EditText mins=oneLine("Minutes");mins.setInputType(InputType.TYPE_CLASS_NUMBER);mins.setText("30");new AlertDialog.Builder(this).setTitle("Timeout").setMessage("Set timeout duration in minutes.").setView(mins).setNegativeButton("Cancel",null).setPositiveButton("Start",(d,w)->{String m=mins.getText().toString().trim().length()>0?mins.getText().toString().trim():"30";cmdWithCallback("lock_timeout",m,resp->{setLocalTimeoutState(true);out(resp);showConnectedParent(false);},err->{out(err);});}).show();}

    void showParentConnection(String prefill){base("Pair child device");currentScreen="pair_parent";root.addView(tv("Enter the child tablet IP address and the pairing code shown on the child device.",15));EditText ip=oneLine("Child IP address");ip.setText(childIp.length()>0?childIp:getSharedPreferences("p",0).getString("childIp",""));EditText code=oneLine("Pairing code");code.setInputType(InputType.TYPE_CLASS_NUMBER);if(prefill!=null&&prefill.length()>0)code.setText(prefill.replaceAll("\\D",""));root.addView(ip);root.addView(code);Button scan=btn("Scan QR");Button pair=btn("Pair");root.addView(scan);root.addView(pair);scan.setOnClickListener(v->startQrScanSafely());pair.setOnClickListener(v->pairWithChild(ip.getText().toString().trim(),code.getText().toString().trim()));root.addView(log);}
    void handlePairQr(String data){String code=data==null?"":data;try{Uri u=Uri.parse(data);String q=u.getQueryParameter("code");if(q!=null)code=q;}catch(Exception ignored){}showParentConnection(code.replaceAll("\\D",""));}
    void pairWithChild(String ip,String code){if(ip.length()==0||code.length()==0){toast("Enter child IP and pairing code");return;}new Thread(()->{try{Socket s=new Socket();s.connect(new InetSocketAddress(ip,PORT),3500);PrintWriter w=new PrintWriter(s.getOutputStream(),true);BufferedReader r=new BufferedReader(new InputStreamReader(s.getInputStream()));w.println("PAIR|"+code+"|"+getSharedPreferences("p",0).getString("localDeviceId",""));String resp=r.readLine();s.close();if(resp!=null&&resp.startsWith("OK|")){String[] parts=resp.split("\\|");String k=parts.length>1?parts[1]:"";runOnUiThread(()->{new SavedConnection(this).saveParentConnection(ip,k);childIp=ip;try{key=Base64.getDecoder().decode(k);}catch(Exception ignored){}unlockedThisRun=true;startService(new Intent(this,ParentMonitorService.class));toast("Paired");showConnectedParent(true);});}else runOnUiThread(()->out(resp==null?"No pairing response":resp));}catch(Exception e){runOnUiThread(()->out("Pairing failed: "+e.getMessage()));}},"Parental-LinkPair").start();}

    void showChildAskParentScreen(){base("Ask Parent");currentScreen="child_requests";root.addView(tv("Send a request to your parent",16));Button unlock=btn("🔓  Ask to unlock device\nRequest access now");Button minutes=btn("⏱️  Ask for 5 more minutes\nRequest more time");Button free=btn("🎁  Ask for free use\nRequest free use today");Button back=btn("Back");root.addView(unlock);root.addView(minutes);root.addView(free);root.addView(back);unlock.setOnClickListener(v->{getSharedPreferences("p",0).edit().putBoolean("askParentRequested",true).putString("askParentReason","unlock device").putLong("askParentAt",System.currentTimeMillis()).apply();toast("Request saved. Keep this device on the same Wi‑Fi.");showChild();});minutes.setOnClickListener(v->{getSharedPreferences("p",0).edit().putBoolean("askParentRequested",true).putString("askParentReason","5 more minutes").putLong("askParentAt",System.currentTimeMillis()).apply();toast("Request saved. Keep this device on the same Wi‑Fi.");showChild();});free.setOnClickListener(v->{getSharedPreferences("p",0).edit().putBoolean("askParentRequested",true).putString("askParentReason","free use").putLong("askParentAt",System.currentTimeMillis()).apply();toast("Request saved. Keep this device on the same Wi‑Fi.");showChild();});back.setOnClickListener(v->showChild());}
    void showChild(){fixedBase("");currentScreen="child";getSharedPreferences("p",0).edit().putString("role","child").apply();startChildService();SharedPreferences p=getSharedPreferences("p",0);boolean connected=p.getBoolean("childConnected",false);ChildHomeScreen.PairViews pv=ChildHomeScreen.render(this,root,connected,childPairingDetailsVisible,p.getString("parentName","Parent Control"),childLocalPermissionsOk(),v->startChildService(),v->showChildSettingsGate(),v->{childPairingDetailsVisible=!childPairingDetailsVisible;showChild();},v->startActivity(new Intent(this,com.enigma.familylinklite.audio.ChildAudioMessageActivity.class)),v->startActivity(new Intent(this,com.enigma.familylinklite.chat.ChildChatActivity.class)),p.getString("lastParentChat","").length()>0,v->showChildAskParentScreen(),v->showLanguageScreen(false),v->showTroubleshootingScreen(),v->showUserMenu());childPairCodeView=pv.code;childCountdownView=pv.countdown;childQrView=pv.qr;updateChildPairingViews();}
    void updateChildPairingViews(){try{byte[] k=getOrCreateKey();String code=currentPairCode(k);if(childPairCodeView!=null)childPairCodeView.setText(code);if(childCountdownView!=null)childCountdownView.setText("IP: "+getIp()+" • New code refreshes automatically");if(childQrView!=null)childQrView.setImageBitmap(qrBitmap("family-link://pair?code="+code,240));}catch(Exception ignored){}}
    void startChildService(){try{getOrCreateKey();Intent i=new Intent(this,ChildServerService.class);if(Build.VERSION.SDK_INT>=26)startForegroundService(i);else startService(i);toast("Child server running");}catch(Exception e){toast("Server start failed");out(e.getMessage());}}
