    void showAddBlockedAppDialog(LinearLayout list){cmdWithCallback("list_apps","",resp->{ArrayList<BlockedAppEntry> apps=BlockedAppEntry.parseInstalledList(resp);if(apps.size()==0){toast("No apps returned");return;}String[] labels=new String[apps.size()];for(int i=0;i<apps.size();i++)labels[i]=apps.get(i).displayName();new AlertDialog.Builder(this).setTitle("Block app").setItems(labels,(d,which)->{BlockedAppEntry e=apps.get(which);cmdWithCallback("block_app",e.pkg,ok->{toast("Blocked");loadBlockedAppsList(list);},err->{toast("Block failed");out(err);});}).show();},err->{toast("Could not list apps");out(err);});}
    void loadBlockedAppsList(LinearLayout list){cmdWithCallback("blocked_apps","",resp->{list.removeAllViews();ArrayList<BlockedAppEntry> apps=BlockedAppEntry.parseList(resp);if(apps.size()==0){list.addView(tv(tr(R.string.no_blocked_apps),15));return;}for(BlockedAppEntry e:apps){LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);TextView name=tv(e.displayName()+(e.untilText.length()>0?"\n"+e.untilText:""),14);Button remove=btn(tr(R.string.remove));row.addView(name,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));row.addView(remove);list.addView(row);remove.setOnClickListener(v->cmdWithCallback("unblock_app",e.pkg,ok->{toast("Removed");loadBlockedAppsList(list);},err->{toast("Remove failed");out(err);}));}},err->{list.removeAllViews();list.addView(tv("Could not load blocked apps",15));out(err);});}


    void showUserMenu(){if(sidePanel!=null&&sidePanel.isShowing()){sidePanel.dismiss();return;}SharedPreferences prefs=getSharedPreferences("p",0);String role=prefs.getString("role","");boolean child="child".equals(role);LinearLayout panel=menuPanel(child?tr(R.string.menu_child_device):"Menu");String[] actions=child?new String[]{"child_home","child_requests","quick_chat","permissions","language","troubleshooting","updates","settings"}:new String[]{"devices","profiles","quick_chat","command_history","logs","troubleshooting","unlock_codes","interface_settings","settings","updates","exit_parent_monitor"};for(String action:actions){Button b=menuButton(action);panel.addView(b);b.setOnClickListener(v->{if(sidePanel!=null)sidePanel.dismiss();handleMenuAction(action);});}TextView version=UiFactory.mutedText(this,"Parental-Link v"+APP_VERSION,12);panel.addView(version);showPanel(panel,Gravity.LEFT|Gravity.TOP);} 
