    String menuLabel(String action){if(action.equals("child_home"))return "Home\nReturn to child dashboard";if(action.equals("child_requests"))return "Requests\nView requests to parent";if(action.equals("permissions"))return "Check permissions\nReview required access";if(action.equals("language"))return "Language\nChoose app language";if(action.equals("ping"))return "Ring device\nPlay a loud sound on the child device";if(action.equals("media_volume"))return "Media volume\nAdjust media volume";if(action.equals("enable_device"))return "Enable device\nTurn on normal access";if(action.equals("stop_timeout"))return "Stop timeout\nEnd the current timeout";if(action.equals("disable_use"))return "Disable use\nBlock device use";if(action.equals("lock_timeout"))return "Timeout\nStart a timed break";if(action.equals("remove_all_limitations"))return "Remove all limitations\nLift restrictions temporarily";if(action.equals("free_use_now"))return "Free use now\nGrant free use";if(action.equals("interface_settings"))return "Interface settings\nChoose custom dashboard actions";if(action.equals("notification_settings"))return "Notification settings\nAllow noisy parent alerts";if(action.equals("devices"))return tr(R.string.menu_devices)+"\nManage child devices";if(action.equals("blocked_apps"))return tr(R.string.menu_blocked_apps)+"\nManage blocked applications";if(action.equals("quick_chat"))return "Quick messages\nSend predefined messages";if(action.equals("command_history"))return tr(R.string.menu_command_history)+"\nView sent commands";if(action.equals("logs"))return tr(R.string.menu_logs)+"\nActivity and system logs";if(action.equals("troubleshooting"))return tr(R.string.menu_troubleshooting)+"\nFix issues and get help";if(action.equals("updates"))return tr(R.string.menu_version_updates)+"\nCheck app version and updates";if(action.equals("profiles"))return tr(R.string.menu_profiles)+"\nManage rules and schedules";if(action.equals("unlock_codes"))return tr(R.string.menu_unlock_codes)+"\nGenerate and manage codes";if(action.equals("settings"))return tr(R.string.menu_settings)+"\nApp and monitoring settings";if(action.equals("add_device"))return tr(R.string.menu_add_device);if(action.equals("exit_parent_monitor"))return tr(R.string.menu_exit_parent_monitor)+"\nStop monitoring this device";if(action.equals("exit"))return tr(R.string.menu_exit);return action;} 
    String shortMenuLabel(String action){String m=menuLabel(action);int i=m.indexOf('\n');return i>=0?m.substring(0,i):m;}
    void showDeviceActionsMenu(){if(sidePanel!=null&&sidePanel.isShowing()){sidePanel.dismiss();return;}SharedPreferences p=getSharedPreferences("p",0);LinearLayout panel=menuPanel("Device actions");panel.addView(UiFactory.mutedText(this,"Quick actions to control the child device.",13));panel.addView(tv("Device control",13));String lockAction=p.getBoolean("parentChildDisabled",false)?"enable_device":"disable_use";String timeoutAction=p.getBoolean("parentTimeoutActive",false)?"stop_timeout":"lock_timeout";String[] control={lockAction,timeoutAction,"remove_all_limitations","media_volume"};for(String action:control){Button b=menuButton(action);panel.addView(b);b.setOnClickListener(v->{if(sidePanel!=null)sidePanel.dismiss();handleMenuAction(action);});}panel.addView(tv("Usage & access",13));String[] usage={"free_use_now","ping","blocked_apps","quick_chat","devices"};for(String action:usage){Button b=menuButton(action);panel.addView(b);b.setOnClickListener(v->{if(sidePanel!=null)sidePanel.dismiss();handleMenuAction(action);});}if(!parentAlertsAllowed()){panel.addView(tv("Parent alerts need notification permission on this phone.",13));Button alert=menuButton("notification_settings");panel.addView(alert);alert.setOnClickListener(v->{if(sidePanel!=null)sidePanel.dismiss();openAppNotificationSettings();});}showPanel(panel,Gravity.RIGHT|Gravity.TOP);}
    void showInterfaceSettingsScreen(){base("Interface settings");currentScreen="interface_settings";root.addView(tv("Appearance",14));Button theme=btn("Theme\n"+themeLabel());root.addView(theme);theme.setOnClickListener(v->showSettingsScreen());root.addView(tv("Dashboard customization",14));Button s1=btn("Quick action slot 1\n"+slotDescription(1));Button s2=btn("Quick action slot 2\n"+slotDescription(2));root.addView(s1);root.addView(s2);s1.setOnClickListener(v->chooseQuickSlot(1));s2.setOnClickListener(v->chooseQuickSlot(2));root.addView(UiFactory.mutedText(this,"Choose which actions appear in the two custom dashboard slots.",13));root.addView(UiFactory.mutedText(this,"Future actions kept in backlog: Screenshot, Battery saver, DND, location update.",13));root.addView(tv("Choose an action",14));String[] actions={"ping","media_volume","quick_chat","blocked_apps","free_use_now","remove_all_limitations","devices","profiles","command_history","troubleshooting"};for(String action:actions){Button b=btn(shortMenuLabel(action));root.addView(b);b.setOnClickListener(v->{chooseSlotThenAction(action);});}root.addView(log);} 
    String themeLabel(){String v=getSharedPreferences("p",0).getString("themeMode","dark");if(v.equals("light"))return "Light mode";if(v.equals("system"))return "Follow device";return "Dark mode";}
    String slotDescription(int slot){String v=getSharedPreferences("p",0).getString("quickSlot"+slot,"");return v.length()==0?"+ Choose action":shortMenuLabel(v);} 
    void chooseSlotThenAction(String action){new AlertDialog.Builder(this).setTitle("Choose slot").setItems(new String[]{"Quick action slot 1","Quick action slot 2"},(d,which)->{getSharedPreferences("p",0).edit().putString("quickSlot"+(which+1),action).apply();showInterfaceSettingsScreen();}).show();}
    void chooseQuickSlot(int slot){String[] actions={"Clear slot","Ring device","Media volume","Quick messages","Blocked apps","Free use now","Remove all limitations","Devices","Profiles","Command history","Troubleshooting"};String[] values={"","ping","media_volume","quick_chat","blocked_apps","free_use_now","remove_all_limitations","devices","profiles","command_history","troubleshooting"};new AlertDialog.Builder(this).setTitle("Quick action slot "+slot).setItems(actions,(d,which)->{getSharedPreferences("p",0).edit().putString("quickSlot"+slot,values[which]).apply();showInterfaceSettingsScreen();}).show();}
    void attachDashboardSwipe(View v){if(v==null)return;v.setOnTouchListener((view,event)->{if(!"dashboard".equals(currentScreen))return false;switch(event.getAction()){case MotionEvent.ACTION_DOWN:swipeStartX=event.getX();swipeStartY=event.getY();return true;case MotionEvent.ACTION_UP:float dx=event.getX()-swipeStartX;float dy=event.getY()-swipeStartY;if(Math.abs(dx)>160&&Math.abs(dx)>Math.abs(dy)*1.6f){if(dx<0)showDeviceActionsMenu();else showUserMenu();return true;}return false;}return false;});}
    void handleMenuAction(String action){if(action.equals("child_home"))showChild();else if(action.equals("child_requests"))showChildAskParentScreen();else if(action.equals("permissions"))showChildSettingsGate();else if(action.equals("language"))showLanguageScreen(false);else if(action.equals("media_volume"))showVolumeScreen();else if(action.equals("enable_device"))cmdWithCallback("enable_use","menu",resp->{setLocalLockState(false);setLocalTimeoutState(false);toast("Device enabled");showConnectedParent(false);},err->{toast("Enable failed");out(err);});else if(action.equals("disable_use"))cmdWithCallback("disable_use","24h",resp->{setLocalLockState(true);toast("Device disabled");showConnectedParent(false);},err->{toast("Disable failed");out(err);});else if(action.equals("stop_timeout"))cmdWithCallback("stop_timeout","menu",resp->{setLocalTimeoutState(false);toast("Timeout stopped");showConnectedParent(false);},err->{toast("Stop timeout failed");out(err);});else if(action.equals("lock_timeout"))showTimeoutDialog();else if(action.equals("remove_all_limitations"))confirmRemoveAllLimitationsCommand();else if(action.equals("logs"))showLogsScreen();else if(action.equals("command_history"))showCommandHistoryScreen();else if(action.equals("troubleshooting"))showTroubleshootingScreen();else if(action.equals("updates"))showVersionScreen();else if(action.equals("devices"))showDevicesScreen();else if(action.equals("add_device"))showParentConnection("");else if(action.equals("blocked_apps"))showBlockedAppsScreen();else if(action.equals("quick_chat"))showQuickChatScreen();else if(action.equals("ping"))cmd("ping","start");else if(action.equals("profiles"))showProfilesScreen();else if(action.equals("unlock_codes"))showUnlockCodesScreen();else if(action.equals("interface_settings"))showInterfaceSettingsScreen();else if(action.equals("free_use_now"))cmdWithCallback("remove_all_limitations","free_use_now",resp->{setLocalLockState(false);setLocalTimeoutState(false);toast("Free use enabled");showConnectedParent(false);},err->{toast("Free use failed");out(err);});else if(action.equals("notification_settings"))openAppNotificationSettings();else if(action.equals("settings")){if("child".equals(getSharedPreferences("p",0).getString("role","")))showChildSettingsGate();else showSettingsScreen();}else if(action.equals("exit_parent_monitor")){stopService(new Intent(this,ParentMonitorService.class));addLog("Parent monitor stopped");toast("Parent monitor stopped");}else if(action.equals("exit")){moveTaskToBack(true);}else toast(action+" will be added later");}
    void showDevicesScreen(){base(tr(R.string.screen_devices));currentScreen="devices";SharedPreferences p=getSharedPreferences("p",0);String role=p.getString("role","");if("child".equals(role)){root.addView(tv(tr(R.string.parents),20));LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);TextView parent=tv("👤 "+p.getString("parentName","Parent Control")+"\nTrusted parent",16);row.addView(parent,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));root.addView(row);root.addView(tv("Only paired parents are shown here. Child devices are managed from the parent app.",13));return;}root.addView(tv(tr(R.string.parents),20));LinearLayout prow=new LinearLayout(this);prow.setOrientation(LinearLayout.HORIZONTAL);TextView parent=tv("👤 "+p.getString("parentName","Parent Control")+"\nThis parent device",16);Button addParent=btn(tr(R.string.add_parent));prow.addView(parent,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));prow.addView(addParent);root.addView(prow);addParent.setOnClickListener(v->showAddParentScaffold());root.addView(tv(tr(R.string.child_devices),20));DeviceProfile deviceProfile=new DeviceProfile(this);LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);TextView d=tv(deviceProfile.childIcon()+" "+deviceProfile.childNickname()+"\n"+deviceProfile.childIp()+"\n"+deviceHealthLine(),17);Button edit=btn("✎");Button remove=btn(tr(R.string.remove));row.addView(d,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));row.addView(edit);row.addView(remove);root.addView(row);edit.setOnClickListener(v->askDeviceDetails(false));remove.setOnClickListener(v->confirmRemoveChildDevice());LinearLayout tools=new LinearLayout(this);tools.setOrientation(LinearLayout.HORIZONTAL);Button test=btn("Test");Button repair=btn("Repair");Button clear=btn("Clear stale");tools.addView(test,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));tools.addView(repair,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));tools.addView(clear,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));root.addView(tools);test.setOnClickListener(v->testChildConnectionFromDevices());repair.setOnClickListener(v->showRepairPairingScreen());clear.setOnClickListener(v->{clearChildStatusOnly();toast("Stale status cleared");showDevicesScreen();});root.addView(tv(tr(R.string.edit_hint_child_device),13));Space sp=new Space(this);root.addView(sp,new LinearLayout.LayoutParams(1,60));Button add=btn("＋ "+tr(R.string.add_device));LinearLayout addRow=new LinearLayout(this);addRow.setGravity(Gravity.RIGHT);addRow.addView(add);root.addView(addRow);add.setOnClickListener(v->showParentConnection(""));}

    void showAddParentScaffold(){base("Add parent");currentScreen="add_parent";root.addView(tv("Second parent workflow",20));root.addView(tv("The first parent will share the new parent information with online child devices. Offline child devices will receive the new parent information on their next heartbeat.",15));root.addView(tv("A secure one-time key will be used before each child performs its own handshake with the new parent.",15));Button back=btn("Back to Devices");root.addView(back);back.setOnClickListener(v->showDevicesScreen());}

    void showQuickChatScreen(){base("Quick messages");currentScreen="quick_chat";root.addView(tv("Send simple emoji prompts. This is not a full chat.",15));root.addView(UiFactory.mutedText(this,"Banner prompts appear at the top-right for 5 minutes and let the child dismiss or snooze. Attention prompts open full screen and can block the device until the parent clears restrictions.",13));final TextView status=tv("Message status will appear here.",14);root.addView(status);Button refresh=btn("Refresh message status");root.addView(refresh);refresh.setOnClickListener(v->refreshQuickMessageStatus(status));root.addView(tv("Preset messages",14));LinearLayout list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,0,1));String[][] presets={{"🍽️","Come to eat"},{"⏱️","5 minutes"},{"🤫","Don't yell"},{"🧹","Tidy up"},{"🛁","Bath time"},{"😴","Bedtime"},{"📞","Call me"}};for(String[] preset:presets){Button b=btn(preset[0]+"  "+preset[1]);list.addView(b);b.setOnClickListener(v->showQuickMessageModeDialog(preset[0],preset[1],status));}Button custom=btn("Custom emoji message");root.addView(custom);custom.setOnClickListener(v->showCustomQuickMessageDialog(status));Button back=btn("Back");root.addView(back);back.setOnClickListener(v->showStartOrSaved());}
    void showQuickMessageModeDialog(String emoji,String text,TextView status){String[] options={"Small banner for 5 minutes","Full-screen attention","Full-screen and block device"};new AlertDialog.Builder(this).setTitle(emoji+"  "+text).setItems(options,(d,which)->{if(which==0)sendQuickMessage("banner",emoji,text,5,false,status);else if(which==1)sendQuickMessage("full",emoji,text,0,false,status);else sendQuickMessage("full",emoji,text,0,true,status);}).show();}
    void showCustomQuickMessageDialog(TextView status){LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);box.setPadding(UiFactory.dp(this,12),UiFactory.dp(this,8),UiFactory.dp(this,12),UiFactory.dp(this,8));EditText emoji=oneLine("Emoji, e.g. 🍽️");EditText text=oneLine("Message, e.g. Come to eat");box.addView(emoji);box.addView(text);new AlertDialog.Builder(this).setTitle("Custom quick message").setView(box).setPositiveButton("Next",(d,w)->{String e=emoji.getText().toString().trim();String t=text.getText().toString().trim();if(e.length()==0)e="💬";if(t.length()==0){toast("Write a message first");return;}showQuickMessageModeDialog(e,t,status);}).setNegativeButton("Cancel",null).show();}
    void sendQuickMessage(String mode,String emoji,String text,int minutes,boolean block,TextView status){String safeEmoji=emoji.replace("|"," ").trim();String safeText=text.replace("|"," ").trim();String payload=mode+"|"+safeEmoji+"|"+safeText+"|"+minutes+"|"+(block?"block":"normal");String quickId="quick_msg_"+System.currentTimeMillis();getSharedPreferences("p",0).edit().putString("lastQuickCommandId",quickId).putString("lastQuickCommandTitle",safeEmoji+" "+safeText).putString("lastQuickPayload",payload).apply();recordCommandStatus(quickId,"quick_chat","Sending","",payload);new CommandClient(this).send(childIp,key,"quick_chat",payload,resp->{recordCommandStatus(quickId,"quick_chat","Delivered",safeEmoji+" "+safeText,payload);toast("Quick message sent");addLog("Activity","Info","Quick message sent",safeEmoji+" "+safeText);status.setText("Sent: "+safeEmoji+" "+safeText+" ("+(mode.equals("banner")?"banner":"full screen")+(block?", blocking":"")+")");},err->{recordCommandStatus(quickId,"quick_chat","Failed",err,payload);toast("Quick message failed");addLog("Commands","Error","Quick message failed",err);status.setText(err);});}
    void refreshQuickMessageStatus(TextView status){cmdWithCallback("chat_status","",resp->{status.setText(resp);updateQuickMessageStatusFromChild(resp);},err->{status.setText(err);out(err);});}
    void updateQuickMessageStatusFromChild(String resp){String compact=compactQuickMessageStatus(resp);if(compact.length()==0)return;SharedPreferences p=getSharedPreferences("p",0);String id=p.getString("lastQuickCommandId","quick_msg_status");String title=p.getString("lastQuickCommandTitle",compact);recordCommandStatus(id,"quick_chat",compact,title,p.getString("lastQuickPayload",""));}
    String compactQuickMessageStatus(String resp){if(resp==null)return "";String line="";for(String l:resp.split("\n")){if(l.startsWith("Child action:")){line=l.substring("Child action:".length()).trim();break;}}if(line.length()==0)return "";int dash=line.indexOf("—");String action=dash>=0?line.substring(dash+1).trim():line;int at=action.indexOf(" at ");if(at>=0)action=action.substring(0,at).trim();String low=action.toLowerCase(java.util.Locale.US);if(low.startsWith("dismissed"))return "Dismissed";if(low.startsWith("snoozed"))return "Snoozed";if(low.startsWith("expired"))return "Expired";if(low.startsWith("asked parent"))return "Asked unlock";return action.length()>0?action:"Updated";}

    void askDeviceDetails(boolean firstRun){base("Edit child device");currentScreen="device_edit";SharedPreferences p=getSharedPreferences("p",0);root.addView(tv("Child device",20));EditText nick=oneLine("Child name");nick.setText(p.getString("childNickname","Child tablet"));root.addView(nick);EditText master=oneLine("Child master password");master.setInputType(InputType.TYPE_CLASS_NUMBER|InputType.TYPE_NUMBER_VARIATION_PASSWORD);master.setFilters(new InputFilter[]{new InputFilter.LengthFilter(6)});master.setText(p.getString("parentPassword",""));root.addView(master);root.addView(tv("Connection",18));root.addView(tv("Saved IP: "+p.getString("childIp","not set")+"\nLast status: "+deviceLastStatusText()+"\nPairing: "+(p.getBoolean("pairingMismatch",false)?"possible mismatch":"normal"),14));Button test=btn("Test connection");Button repair=btn("Repair pairing");Button clearStale=btn("Clear stale status");root.addView(test);root.addView(repair);root.addView(clearStale);test.setOnClickListener(v->testChildConnection());repair.setOnClickListener(v->showRepairPairingScreen());clearStale.setOnClickListener(v->{clearChildStatusOnly();toast("Stale status cleared");askDeviceDetails(false);});root.addView(tv("Language",18));Button language=btn("Child language: "+LanguageManager.label(p.getString("childLanguage","system")));root.addView(language);language.setOnClickListener(v->showLanguageScreen(true));Button save=btn(tr(R.string.save));root.addView(save);save.setOnClickListener(v->{String pass=master.getText().toString().trim();if(pass.length()>0&&(pass.length()<4||pass.length()>6)){toast("Use 4 to 6 digits for the child master password");return;}p.edit().putString("childNickname",nick.getText().toString().trim().length()>0?nick.getText().toString().trim():"Child tablet").putString("parentPassword",pass).apply();if(pass.length()>0)cmdWithCallback("set_parent_password",p.getString("parentName","Parent Control")+"|"+pass,resp->{toast("Saved");showDevicesScreen();},err->{toast("Saved locally. Child update failed.");showDevicesScreen();});else showDevicesScreen();});}

    String deviceLastStatusText(){long last=getSharedPreferences("p",0).getLong("lastStatusMs",0);if(last<=0)return "never";long min=(System.currentTimeMillis()-last)/60000;return min<=0?"just now":min+" min ago";}
    String deviceHealthLine(){SharedPreferences p=getSharedPreferences("p",0);if(p.getBoolean("pairingMismatch",false))return "🔴 Repair pairing needed";long last=p.getLong("lastStatusMs",0);if(last<=0)return "🟡 No child status yet";long min=(System.currentTimeMillis()-last)/60000;if(min>10)return "🟡 Stale • last sync "+min+" min ago";return "🟢 Online • last sync "+(min<=0?"just now":min+" min ago");}
    void clearChildStatusOnly(){getSharedPreferences("p",0).edit().remove("remoteVersion").remove("remoteProtocol").remove("remotePermissions").remove("remoteCapabilities").remove("remoteDnd").remove("lastCurrentApp").remove("lastStatusMs").remove("todayMinutes").remove("remoteBattery").remove("remoteCharging").remove("remoteWifiBars").remove("devicesNotificationSummary").remove("pairingMismatch").remove("pairingMismatchMessage").apply();try{startService(new Intent(this,ParentMonitorService.class));}catch(Exception ignored){}}
    void testChildConnection(){cmdWithCallback("hello","",resp->{toast("Child responded");addLog("Connection","Info","Child connection test",resp);getSharedPreferences("p",0).edit().putBoolean("pairingMismatch",false).remove("pairingMismatchMessage").apply();askDeviceDetails(false);},err->{toast("Connection test failed");addLog("Connection","Error","Child connection test failed",err);askDeviceDetails(false);});}
    void testChildConnectionFromDevices(){cmdWithCallback("hello","",resp->{toast("Child responded");addLog("Connection","Info","Child connection test",resp);getSharedPreferences("p",0).edit().putBoolean("pairingMismatch",false).remove("pairingMismatchMessage").apply();showDevicesScreen();},err->{toast("Connection test failed");addLog("Connection","Error","Child connection test failed",err);showDevicesScreen();});}
    void showRepairPairingScreen(){base("Repair pairing");currentScreen="repair_pairing";SharedPreferences p=getSharedPreferences("p",0);root.addView(tv("Use this if the child app was reset, the IP belongs to another device, or the saved pairing is stale.",15));EditText ip=oneLine("Child IP address");ip.setText(p.getString("childIp",childIp));EditText code=oneLine("New pairing code");code.setInputType(InputType.TYPE_CLASS_NUMBER);root.addView(ip);root.addView(code);Button scan=btn("Scan QR");Button repair=btn("Repair pairing");Button back=btn("Back");root.addView(scan);root.addView(repair);root.addView(back);scan.setOnClickListener(v->startQrScanSafely());repair.setOnClickListener(v->{String newIp=ip.getText().toString().trim();String newCode=code.getText().toString().trim();if(newIp.length()==0||newCode.length()==0){toast("Enter child IP and code");return;}clearChildStatusOnly();pairWithChild(newIp,newCode);});back.setOnClickListener(v->askDeviceDetails(false));root.addView(log);}

    void showLanguageScreen(boolean targetChild){base("Language");currentScreen=targetChild?"child_language":"language";SharedPreferences p=getSharedPreferences("p",0);String current=targetChild?p.getString("childLanguage","system"):LanguageManager.current(this);root.addView(tv(targetChild?tr(R.string.screen_language_child):tr(R.string.screen_language_app),18));root.addView(tv(tr(R.string.language_help),13));RadioGroup group=new RadioGroup(this);group.setOrientation(RadioGroup.VERTICAL);String[] values={"system","en","el","fr"};for(String val:values){RadioButton rb=new RadioButton(this);rb.setId(View.generateViewId());rb.setText(LanguageManager.label(val));rb.setTag(val);group.addView(rb);if(val.equals(current))group.check(rb.getId());}root.addView(group);Button save=btn(tr(R.string.save));root.addView(save);save.setOnClickListener(v->{RadioButton rb=group.findViewById(group.getCheckedRadioButtonId());String lang=rb==null?"system":String.valueOf(rb.getTag());if(targetChild){p.edit().putString("childLanguage",lang).apply();cmdWithCallback("set_language",lang,resp->{toast(tr(R.string.child_language_saved));showDevicesScreen();},err->{toast(tr(R.string.saved_locally_child_failed));showDevicesScreen();});}else{LanguageManager.set(this,lang);toast(tr(R.string.language_saved));recreate();}});}

    void confirmRemoveChildDevice(){SharedPreferences p=getSharedPreferences("p",0);String child=p.getString("childNickname","Child tablet");String master=p.getString("parentPassword","");String msg="Remove "+child+" from this parent app?";new AlertDialog.Builder(this).setTitle("Remove child device?").setMessage(msg+"\n\nIf the child is online, Parental-Link will remove the parent link from the child first. If it is offline, write down the child master password before removing it locally.\n\nMaster password: "+(master.length()>0?master:"not set")).setNegativeButton("Cancel",null).setPositiveButton("Continue",(d,w)->tryRemoveChildDeviceOnline()).show();}

    void tryRemoveChildDeviceOnline(){cmdWithCallback("remove_parental_link","parent_removed",resp->{addLog("Security","Info","Child device removed",resp);removeChildLocally();},err->{showOfflineChildRemovalWarning(err);});}

    void showOfflineChildRemovalWarning(String err){String master=getSharedPreferences("p",0).getString("parentPassword","");AlertDialog dlg=new AlertDialog.Builder(this).setTitle("Child device is offline").setMessage("The child device did not acknowledge removal. Removing it now may leave Parental-Link active on the child device.\n\nWrite down the child master password and use it on the child device: Unlock settings → Remove Parental-Link settings.\n\nMaster password: "+(master.length()>0?master:"not set")+"\n\nError: "+err).setNegativeButton("Cancel",null).setPositiveButton("Remove locally in 5",null).create();dlg.setOnShowListener(di->{Button b=dlg.getButton(AlertDialog.BUTTON_POSITIVE);b.setEnabled(false);final int[] r={5};Runnable tick=new Runnable(){public void run(){if(!dlg.isShowing())return;if(r[0]>0){b.setText("Remove locally in "+r[0]);r[0]--;handler.postDelayed(this,1000);}else{b.setText("Remove locally");b.setEnabled(true);}}};tick.run();b.setOnClickListener(v->{dlg.dismiss();removeChildLocally();});});dlg.show();}

    void removeChildLocally(){getSharedPreferences("p",0).edit()
            .remove("childIp").remove("parentKey").remove("childNickname").remove("childIcon")
            .remove("remoteVersion").remove("remoteProtocol").remove("remotePermissions")
            .remove("remoteCapabilities").remove("remoteDnd").remove("lastCurrentApp")
            .remove("lastStatusMs").remove("todayMinutes").remove("remoteBattery")
            .remove("remoteCharging").remove("remoteWifiBars").remove("devicesNotificationSummary")
            .remove("childRemovalRequested").remove("childRemovalMethod").remove("childRemovalPending").remove("pairingMismatch").remove("pairingMismatchMessage").remove("childUnlockRequestPending").remove("childUnlockRequestReason").remove("childUnlockRequestAt").remove("childUnlockSnoozeUntil")
            .putBoolean("childDeviceRemoved",true)
            .apply();
        try{startService(new Intent(this,ParentMonitorService.class));}catch(Exception ignored){}
        addLog("Security","Info","Child device removed locally","Parent app removed saved child connection");
        toast("Child device removed");showStartOrSaved();}
    void showProfilesScreen(){base("Profiles");currentScreen="profiles";root.addView(tv("Profiles send a group of rules to the child tablet. Full scheduled rules can be added later.",15));Button homework=btn("Homework mode");Button bedtime=btn("Bedtime mode");Button free=btn("Free use: remove all limitations");root.addView(homework);root.addView(bedtime);root.addView(free);homework.setOnClickListener(v->cmd("profile","homework"));bedtime.setOnClickListener(v->cmd("profile","bedtime"));free.setOnClickListener(v->confirmRemoveAllLimitationsCommand());Button back=btn("Back to dashboard");root.addView(back);back.setOnClickListener(v->showStartOrSaved());}
    void confirmRemoveAllLimitationsCommand(){new AlertDialog.Builder(this).setTitle("Remove all limitations?").setMessage("This sends a Free use command to the child device. It removes timeout, disable mode, active profile and blocked-app limitations.").setNegativeButton("Cancel",null).setPositiveButton("Remove all",(d,w)->cmd("remove_all_limitations","free_use")).show();}
    void showSecondParentScreen(){base("Second parent");currentScreen="second_parent";root.addView(tv("Second-parent approval groundwork. A second parent should be approved by the first parent before the child accepts the new device.",15));root.addView(tv("Current parent identity: "+getSharedPreferences("p",0).getString("parentName","Parent Control")+"\nDevice ID: "+getSharedPreferences("p",0).getString("localDeviceId",""),14));Button request=btn("Create approval request scaffold");root.addView(request);request.setOnClickListener(v->{getSharedPreferences("p",0).edit().putBoolean("securityAttention",true).apply();addLog("Second parent approval request created");toast("Approval request scaffold created");});Button back=btn("Back to dashboard");root.addView(back);back.setOnClickListener(v->showStartOrSaved());}

    void showLogsScreen(){base("Logs");currentScreen="logs";SharedPreferences p=getSharedPreferences("p",0);LinearLayout controls=new LinearLayout(this);controls.setOrientation(LinearLayout.HORIZONTAL);Button one=btn("One line");Button full=btn("Full status");Button clear=btn("Clear logs");controls.addView(one,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));controls.addView(full,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));controls.addView(clear,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));root.addView(controls);LinearLayout filters=new LinearLayout(this);filters.setOrientation(LinearLayout.HORIZONTAL);final String[] currentFilter={"All"};String[] fs={"All","Activity","Security","Connection","Commands","Debug"};for(String f:fs){Button fb=btn(f);filters.addView(fb);fb.setOnClickListener(v->{currentFilter[0]=((Button)v).getText().toString();renderLogsList(p.getString("logs",""),currentFilter[0],false);});}root.addView(filters);one.setOnClickListener(v->renderLogsList(p.getString("logs",""),currentFilter[0],false));full.setOnClickListener(v->renderLogsList(p.getString("logs",""),currentFilter[0],true));clear.setOnClickListener(v->new AlertDialog.Builder(this).setTitle("Clear logs?").setMessage("This will remove the event history from this device.").setNegativeButton("Cancel",null).setPositiveButton("Clear",(d,w)->{getSharedPreferences("p",0).edit().remove("logs").remove("latestLog").apply();showLogsScreen();}).show());renderLogsList(p.getString("logs",""),"All",false);} 
    void renderLogsList(String raw,String filter,boolean full){while(root.getChildCount()>4)root.removeViewAt(4);if(raw==null||raw.trim().length()==0){root.addView(tv("No logs yet",15));return;}String[] lines=raw.split("\n");for(String line:lines){if(line.trim().length()==0)continue;if(!"All".equals(filter)&&!line.contains("["+filter+"/"))continue;TextView row=tv(full?AppLog.detail(line):AppLog.lineSummary(line),14);row.setSingleLine(!full);row.setEllipsize(TextUtils.TruncateAt.END);row.setOnClickListener(v->new AlertDialog.Builder(this).setTitle("Log details").setMessage(AppLog.detail(line)).setPositiveButton("OK",null).show());root.addView(row);} }


    void showCommandHistoryScreen(){base(tr(R.string.command_history_title));currentScreen="command_history";root.addView(tv(tr(R.string.command_history_help),14));LinearLayout list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,0,1));renderCommandHistoryRows(list);LinearLayout actions=new LinearLayout(this);actions.setOrientation(LinearLayout.HORIZONTAL);Button clear=btn(tr(R.string.clear));Button refresh=btn(tr(R.string.refresh));actions.addView(clear,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));actions.addView(refresh,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));root.addView(actions);clear.setOnClickListener(v->{CommandStatusStore.clear(this);showCommandHistoryScreen();});refresh.setOnClickListener(v->showCommandHistoryScreen());}
    void renderCommandHistoryRows(LinearLayout list){list.removeAllViews();String raw=getSharedPreferences("p",0).getString("commandLifecycleHistory","");if(raw.trim().length()==0){list.addView(tv("No command history",15));return;}java.text.SimpleDateFormat fmt=new java.text.SimpleDateFormat("HH:mm:ss",java.util.Locale.US);for(String row:raw.split("\\n")){String[] p=row.split("\\|",-1);if(p.length<4)continue;long t=0;try{t=Long.parseLong(p[0]);}catch(Exception ignored){}String time=t>0?fmt.format(new java.util.Date(t)):"--:--";String command=p[2];String status=p[3];String details=p.length>4?p[4]:"";String value=p.length>5?p[5]:"";LinearLayout line=new LinearLayout(this);line.setOrientation(LinearLayout.HORIZONTAL);TextView item=tv(time+"  "+(command.equals("quick_chat")?compactActivityLine(command,status,details,value):commandIcon(command,status)+" "+command+" — "+status+(details.length()>0?"\\n"+shortText(details,90):"")),13);line.addView(item,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));if("Failed".equalsIgnoreCase(status)){Button retry=btn("Retry");line.addView(retry);retry.setOnClickListener(v->{cmdWithCallback(command,value,resp->{toast(tr(R.string.retry_executed));showCommandHistoryScreen();},err->{toast(tr(R.string.retry_failed));showCommandHistoryScreen();});});}line.setOnClickListener(v->new AlertDialog.Builder(this).setTitle(command+" — "+status).setMessage("Time: "+time+"\\nDetails: "+details+"\\nValue: "+value).setPositiveButton("OK",null).show());list.addView(line);}}
    String commandIcon(String command,String status){String s=(command+" "+status).toLowerCase(java.util.Locale.US);if(s.contains("failed"))return "❌";if(s.contains("sending"))return "…";if(s.contains("ping"))return "📢";if(s.contains("timeout"))return "⏱";if(s.contains("disable")||s.contains("lock"))return "🔒";if(s.contains("volume"))return "🔊";if(s.contains("mute"))return "🔇";if(s.contains("chat")||s.contains("message"))return "💬";if(s.contains("call"))return "☎";if(s.contains("block"))return "🚫";return "✓";}
    String shortText(String s,int max){if(s==null)return "";return s.length()<=max?s:s.substring(0,Math.max(0,max-1))+"…";}

    void showTroubleshootingScreen(){base("Troubleshooting");currentScreen="troubleshooting";SharedPreferences p=getSharedPreferences("p",0);String role=p.getString("role","");if("child".equals(role)){root.addView(tv("Parent app",18));root.addView(tv("Parent: "+p.getString("parentName","Parent Control")+"\nConnection: "+(p.getBoolean("childConnected",false)?"connected":"waiting")+"\nServer: running",14));root.addView(tv("Child device info",18));root.addView(tv("Device ID: "+p.getString("localDeviceId","unknown")+"\nIP: "+getIp()+"\nVersion: "+APP_VERSION+"\nProtocol: "+PROTOCOL_VERSION+"\nPermissions: "+childLocalPermissionSummary(),14));Button logs=btn("Open logs");Button restart=btn("Restart server");root.addView(logs);root.addView(restart);logs.setOnClickListener(v->showLogsScreen());restart.setOnClickListener(v->startChildService());return;}root.addView(tv("Connection diagnostics",18));if(p.getBoolean("pairingMismatch",false)){root.addView(tv("🔴 Possible pairing mismatch",20));root.addView(tv(p.getString("pairingMismatchMessage","A server answered at the saved child IP, but it did not match this paired child device."),14));Button removeStale=btn("Remove stale device");root.addView(removeStale);removeStale.setOnClickListener(v->confirmRemoveChildDevice());}root.addView(tv("Parent",16));root.addView(tv("Local IP: "+getIp()+"\nChild IP: "+(childIp.length()>0?childIp:"unknown")+"\nProtocol: "+PROTOCOL_VERSION+" / minimum supported: "+MIN_PROTOCOL,14));long last=p.getLong("lastStatusMs",0);String lastText=last>0?((System.currentTimeMillis()-last)/60000)+" min ago":"never";root.addView(tv("Child",16));root.addView(tv("Last status: "+lastText+"\nVersion: "+p.getString("remoteVersion","unknown")+"\nProtocol: "+p.getString("remoteProtocol","unknown")+"\nPermissions: "+p.getString("remotePermissions","unknown")+"\nDND: "+p.getString("remoteDnd","unknown")+"\nCurrent app: "+currentAppDisplay(),14));root.addView(tv("Actions",18));Button refresh=btn("Refresh diagnostics");Button logs=btn("Open logs");Button export=btn("Export logs");Button restartParent=btn("Restart parent monitor");root.addView(refresh);root.addView(logs);root.addView(export);root.addView(restartParent);refresh.setOnClickListener(v->{cmdWithCallback("usage","today",resp->{updateUsageViews(resp,tv("",1),null);addLog("Connection","Info","Diagnostics refreshed",resp);showTroubleshootingScreen();},err->{addLog("Connection","Error","Diagnostics refresh failed",err);out(err);});});logs.setOnClickListener(v->showLogsScreen());export.setOnClickListener(v->{String data=getSharedPreferences("p",0).getString("logs","");Intent send=new Intent(Intent.ACTION_SEND);send.setType("text/plain");send.putExtra(Intent.EXTRA_SUBJECT,"Parental-Link logs");send.putExtra(Intent.EXTRA_TEXT,data.length()>0?data:"No logs");startActivity(Intent.createChooser(send,"Export logs"));});restartParent.setOnClickListener(v->{stopService(new Intent(this,ParentMonitorService.class));startService(new Intent(this,ParentMonitorService.class));addLog("Connection","Info","Parent monitor restarted","Restarted from troubleshooting");toast("Parent monitor restarted");});}
    void showVersionScreen(){base(tr(R.string.menu_version_updates));currentScreen="updates";SharedPreferences p=getSharedPreferences("p",0);String role=p.getString("role","");root.addView(tv(tr(R.string.current_version)+": "+APP_VERSION,16));root.addView(tv("Protocol: "+PROTOCOL_VERSION+" / minimum supported: "+MIN_PROTOCOL,16));if("child".equals(role)){root.addView(tv("Parent: "+p.getString("parentName","Parent Control"),14));Button inform=btn("Inform parent about this version");root.addView(inform);inform.setOnClickListener(v->{addLog("Version information opened on child device");toast("Parent will see the version on next connection.");});Button back=btn(tr(R.string.back));root.addView(back);back.setOnClickListener(v->showChild());return;}String remote=p.getString("remoteVersion","");String remoteProtocol=p.getString("remoteProtocol","");root.addView(tv(remote.length()>0?"Child version: "+remote+(remoteProtocol.length()>0?" / protocol "+remoteProtocol:""):"Child version: unknown until next successful command",16));String latest=p.getString("latestVersion","");TextView status=tv(latest.length()>0?"Latest GitHub release: "+latest:"Latest GitHub release: not checked",16);root.addView(status);root.addView(tv("Repository: "+DEFAULT_REPO,14));Button check=btn(tr(R.string.check_for_updates));Button open=btn(tr(R.string.open_latest_release));root.addView(check);root.addView(open);check.setOnClickListener(v->checkLatestRelease(DEFAULT_REPO,status));open.setOnClickListener(v->{String url=getSharedPreferences("p",0).getString("latestReleaseUrl","");if(url.length()==0)toast("Check for updates first");else startActivity(new Intent(Intent.ACTION_VIEW,Uri.parse(url)));});root.addView(tv("Tablet updates should be initiated by the parent. Update source is fixed for safety.",14));Button back=btn("Back to dashboard");root.addView(back);back.setOnClickListener(v->showStartOrSaved());}
    boolean childLocalPermissionsOk(){return isDeviceAdminActive()&&hasUsageAccess()&&isAccessibilityEnabled()&&hasNotificationPermission()&&hasOverlayPermission()&&hasNotificationPolicyAccess()&&isBatteryUnrestricted();}
    boolean hasNotificationPermission(){try{return Build.VERSION.SDK_INT<33||checkSelfPermission(Manifest.permission.POST_NOTIFICATIONS)==PackageManager.PERMISSION_GRANTED;}catch(Exception e){return false;}}
    boolean hasNotificationPolicyAccess(){try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);return nm!=null&&nm.isNotificationPolicyAccessGranted();}catch(Exception e){return false;}}
    boolean hasOverlayPermission(){try{if(Build.VERSION.SDK_INT<23)return true;if(Settings.canDrawOverlays(this))return true;AppOpsManager a=(AppOpsManager)getSystemService(APP_OPS_SERVICE);if(a!=null){int mode=a.checkOpNoThrow(AppOpsManager.OPSTR_SYSTEM_ALERT_WINDOW,android.os.Process.myUid(),getPackageName());return mode==AppOpsManager.MODE_ALLOWED;}}catch(Exception ignored){}return false;}
    boolean isBatteryUnrestricted(){try{PowerManager pm=(PowerManager)getSystemService(POWER_SERVICE);return pm!=null&&pm.isIgnoringBatteryOptimizations(getPackageName());}catch(Exception e){return false;}}
    void openOverlayPermissionSettings(){Intent i=new Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION,Uri.parse("package:"+getPackageName()));try{startActivity(i);}catch(Exception e){try{startActivity(new Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION));}catch(Exception ignored){startActivity(new Intent(Settings.ACTION_SETTINGS));}}}
    void openBatteryPermissionSettings(){try{if(Build.VERSION.SDK_INT>=23&&!isBatteryUnrestricted()){Intent i=new Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS,Uri.parse("package:"+getPackageName()));startActivity(i);return;}}catch(Exception ignored){}try{startActivity(new Intent(Settings.ACTION_IGNORE_BATTERY_OPTIMIZATION_SETTINGS));}catch(Exception e){startActivity(new Intent(Settings.ACTION_SETTINGS));}}
    String childLocalPermissionSummary(){return "admin="+isDeviceAdminActive()+", usage="+hasUsageAccess()+", accessibility="+isAccessibilityEnabled()+", notifications="+hasNotificationPermission()+", overlay="+hasOverlayPermission()+", dndPolicy="+hasNotificationPolicyAccess()+", battery="+isBatteryUnrestricted();}

    void showChildSettingsGate(){base("Unlock settings");currentScreen="child_settings_gate";SharedPreferences p=getSharedPreferences("p",0);root.addView(tv("Enter a one-time code from the parent app or the child master password.",15));EditText code=oneLine("Code or master password");code.setInputType(InputType.TYPE_CLASS_NUMBER|InputType.TYPE_NUMBER_VARIATION_PASSWORD);code.setFilters(new InputFilter[]{new InputFilter.LengthFilter(6)});root.addView(code);Button unlock=btn("Unlock settings");Button back=btn("Back to dashboard");root.addView(unlock);root.addView(back);unlock.setOnClickListener(v->{String entered=code.getText().toString().trim();String master=p.getString("parentPassword","");String otp=p.getString("childOtp","");if(entered.length()==0){toast("Enter a code");return;}if(otp.length()>0&&entered.equals(otp)){p.edit().remove("childOtp").remove("childOtpParent").apply();showChildSettings("one-time code");return;}if(master.length()>0&&entered.equals(master)){showChildSettings("master password");return;}addLog("Wrong child settings unlock attempt");toast("Wrong code");});back.setOnClickListener(v->showChild());}

    void startQrScanSafely(){try{if(Build.VERSION.SDK_INT>=23&&checkSelfPermission(Manifest.permission.CAMERA)!=PackageManager.PERMISSION_GRANTED){requestPermissions(new String[]{Manifest.permission.CAMERA},CAMERA_SCAN_REQUEST);toast("Allow camera permission, then press Scan QR again");return;}IntentIntegrator integrator=new IntentIntegrator(this);integrator.setPrompt("Scan child pairing QR");integrator.setBeepEnabled(false);integrator.setOrientationLocked(false);integrator.initiateScan();}catch(Exception e){toast("QR scanner unavailable. Enter the pairing code manually.");addLog("QR scan failed: "+e.getClass().getSimpleName());}}

    void showChildSettings(String method){base(tr(R.string.child_settings));currentScreen="child_settings";root.addView(tv(tr(R.string.unlocked_with)+": "+method,14));root.addView(tv(tr(R.string.connection_information),18));root.addView(tv("Parent: "+getSharedPreferences("p",0).getString("parentName","Parent Control")+"\nDevice ID: "+getSharedPreferences("p",0).getString("localDeviceId","unknown")+"\nIP: "+getIp()+"\nServer: running",14));root.addView(tv(childLocalPermissionsOk()?"🟢 "+tr(R.string.required_access_ok):"🔴 "+tr(R.string.new_permissions_needed),16));root.addView(tv(tr(R.string.required_access),18));addPermissionRow(tr(R.string.device_administrator),isDeviceAdminActive(),v->startActivity(new Intent(DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN).putExtra(DevicePolicyManager.EXTRA_DEVICE_ADMIN,new ComponentName(this,AdminReceiver.class))));addPermissionRow(tr(R.string.usage_access),hasUsageAccess(),v->startActivity(new Intent(Settings.ACTION_USAGE_ACCESS_SETTINGS)));addPermissionRow(tr(R.string.accessibility_service),isAccessibilityEnabled(),v->startActivity(new Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS)));addPermissionRow(tr(R.string.notifications),hasNotificationPermission(),v->{if(Build.VERSION.SDK_INT>=33)requestPermissions(new String[]{Manifest.permission.POST_NOTIFICATIONS},7);else toast("Notifications are already allowed on this Android version");});addPermissionRow(tr(R.string.display_over_other_apps),hasOverlayPermission(),v->openOverlayPermissionSettings());addPermissionRow(tr(R.string.dnd_policy_access),hasNotificationPolicyAccess(),v->startActivity(new Intent(Settings.ACTION_NOTIFICATION_POLICY_ACCESS_SETTINGS)));addPermissionRow(tr(R.string.battery_unrestricted),isBatteryUnrestricted(),v->openBatteryPermissionSettings());Button check=btn(tr(R.string.check_again));Button restart=btn(tr(R.string.restart_server));Button travel=btn(tr(R.string.remove_all_limitations_travel));Button remove=btn(tr(R.string.remove_parental_control));root.addView(check);root.addView(restart);root.addView(travel);root.addView(remove);check.setOnClickListener(v->showChildSettings(method));restart.setOnClickListener(v->startChildService());travel.setOnClickListener(v->confirmChildTravelMode(method));remove.setOnClickListener(v->confirmRemoveApp(method));root.addView(log);listenLogs();}
    void addPermissionRow(String name,boolean ok,View.OnClickListener action){LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);TextView t=tv((ok?"✅ ":"⚠ ")+name,15);row.addView(t,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));if(!ok){Button b=btn("Enable");b.setOnClickListener(action);row.addView(b);}root.addView(row);}

    void confirmChildTravelMode(String method){new AlertDialog.Builder(this).setTitle(tr(R.string.remove_all_limitations_title)).setMessage(tr(R.string.remove_all_limitations_msg)+"\n\n"+tr(R.string.authorised_by)+": "+method).setNegativeButton("Cancel",null).setPositiveButton(tr(R.string.remove_limitations),(d,w)->{removeAllLocalLimitations(method);showChildSettings(method);}).show();}
    void removeAllLocalLimitations(String method){SharedPreferences prefs=getSharedPreferences("rules",0);SharedPreferences.Editor ed=prefs.edit();for(String k:prefs.getAll().keySet()){if(k.startsWith("blocked_until_"))ed.remove(k);}ed.remove("lock_until").remove("lock_mode").remove("active_profile").remove("profile_until").apply();sendBroadcast(new Intent("com.enigma.familylinklite.CLOSE_ATTENTION"));addLog("Security","Info","Travel mode enabled","All local limitations removed by "+method);toast("All limitations removed");}

    boolean isDeviceAdminActive(){try{DevicePolicyManager dpm=(DevicePolicyManager)getSystemService(DEVICE_POLICY_SERVICE);return dpm!=null&&dpm.isAdminActive(new ComponentName(this,AdminReceiver.class));}catch(Exception e){return false;}}
    boolean hasUsageAccess(){try{AppOpsManager a=(AppOpsManager)getSystemService(APP_OPS_SERVICE);int mode=a.checkOpNoThrow(AppOpsManager.OPSTR_GET_USAGE_STATS,android.os.Process.myUid(),getPackageName());return mode==AppOpsManager.MODE_ALLOWED;}catch(Exception e){return false;}}
    boolean isAccessibilityEnabled(){try{String enabled=Settings.Secure.getString(getContentResolver(),Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES);return enabled!=null&&enabled.toLowerCase(Locale.US).contains(getPackageName().toLowerCase(Locale.US));}catch(Exception e){return false;}}
    void confirmRemoveApp(String method){new AlertDialog.Builder(this).setTitle(tr(R.string.remove_settings_title)).setMessage(tr(R.string.remove_settings_msg)+"\n\n"+tr(R.string.authorised_by)+": "+method).setNegativeButton("Cancel",null).setPositiveButton(tr(R.string.request_removal),(d,w)->{requestChildRemoval(method);}).show();}

    void requestChildRemoval(String method){SharedPreferences p=getSharedPreferences("p",0);p.edit().putBoolean("childRemovalRequested",true).putString("childRemovalMethod",method).putLong("childRemovalRequestedAt",System.currentTimeMillis()).apply();addLog("Security","Warning","Child requested removal of Parental-Link settings","Authorised by: "+method);showChildRemovalPending(method);}

    void showChildRemovalPending(String method){base(tr(R.string.removal_requested));currentScreen="child_removal_pending";root.addView(tv(tr(R.string.parent_informed_next_connection),16));root.addView(tv(tr(R.string.authorised_by)+": "+method,14));root.addView(tv("Keep this tablet on the same Wi-Fi until the parent confirms removal. If the parent is not available, you can remove local settings manually below.",14));Button check=btn(tr(R.string.check_again));Button force=btn(tr(R.string.remove_local_settings_now));Button back=btn(tr(R.string.back));root.addView(check);root.addView(force);root.addView(back);check.setOnClickListener(v->showChildRemovalPending(method));force.setOnClickListener(v->{clearChildParentalLinkSettings();toast(tr(R.string.settings_removed_locally));showStart();});back.setOnClickListener(v->showChild());}

    void clearChildParentalLinkSettings(){try{getSharedPreferences("rules",0).edit().clear().apply();}catch(Exception ignored){}SharedPreferences p=getSharedPreferences("p",0);String id=p.getString("localDeviceId",UUID.randomUUID().toString());p.edit().clear().putString("localDeviceId",id).apply();}
    void showSettingsScreen(){base(tr(R.string.menu_settings));currentScreen="settings";root.addView(tv(tr(R.string.appearance),18));root.addView(tv(tr(R.string.theme),15));RadioGroup theme=new RadioGroup(this);theme.setOrientation(RadioGroup.VERTICAL);String currentTheme=getSharedPreferences("p",0).getString("themeMode","system");String[] labels={tr(R.string.follow_device),tr(R.string.light),tr(R.string.dark)};String[] values={"system","light","dark"};for(int i=0;i<labels.length;i++){RadioButton rb=new RadioButton(this);rb.setId(View.generateViewId());rb.setText(labels[i]);rb.setTag(values[i]);theme.addView(rb);if(values[i].equals(currentTheme))theme.check(rb.getId());}theme.setOnCheckedChangeListener((g,id)->{RadioButton rb=g.findViewById(id);if(rb!=null){getSharedPreferences("p",0).edit().putString("themeMode",String.valueOf(rb.getTag())).apply();toast(tr(R.string.theme_saved));}});root.addView(theme);root.addView(tv("Language",18));Button lang=btn(LanguageManager.languageMenuLabel(this));root.addView(lang);lang.setOnClickListener(v->showLanguageScreen(false));root.addView(tv(tr(R.string.security),18));Button remove=btn(tr(R.string.remove_parental_control));root.addView(remove);remove.setOnClickListener(v->confirmRemoveParentalControl());root.addView(tv("This removes only Parental-Link settings on this device. It does not reset the phone, tablet, or TV.",13));}
    void confirmRemoveParentalControl(){SharedPreferences p=getSharedPreferences("p",0);String otherParent=p.getString("otherParentName","");String devices=childDeviceListText();StringBuilder msg=new StringBuilder();msg.append("This does not reset the device,\n");msg.append("it only removes the settings of the Parental-Link application on your device.\n\n");if(otherParent.length()>0){msg.append("The Parental-Link application of ").append(otherParent).append(" will continue to control the following devices:\n").append(devices);}else{msg.append("The Parental-Link application will delete its settings and a new first-time connection will be available for the following devices:\n").append(devices);}AlertDialog dlg=new AlertDialog.Builder(this).setTitle("Remove parental control?").setMessage(msg.toString()).setNegativeButton("Cancel",null).setPositiveButton("Remove in 5",null).create();dlg.setOnShowListener(di->{Button b=dlg.getButton(AlertDialog.BUTTON_POSITIVE);b.setEnabled(false);final int[] remaining={5};Runnable tick=new Runnable(){public void run(){if(!dlg.isShowing())return;if(remaining[0]>0){b.setText("Remove in "+remaining[0]);remaining[0]--;handler.postDelayed(this,1000);}else{b.setText("Remove");b.setEnabled(true);}}};tick.run();b.setOnClickListener(v->{dlg.dismiss();resetLocalParentalLinkData();});});dlg.show();}

    String childDeviceListText(){SharedPreferences p=getSharedPreferences("p",0);String nickname=p.getString("childNickname","Child device");String ip=p.getString("childIp","");String line="• "+nickname+(ip.length()>0?" ("+ip+")":"");return line+"\n";}

    void resetLocalParentalLinkData(){try{stopService(new Intent(this,ParentMonitorService.class));}catch(Exception ignored){}getSharedPreferences("p",0).edit().clear().apply();unlockedThisRun=false;authPromptLaunched=false;childIp="";key=null;toast("Parental-Link settings removed");showStart();}
    void showUnlockCodesScreen(){base("Unlock codes");currentScreen="unlock_codes";TextView current=tv("No active one-time code",22);current.setGravity(Gravity.CENTER);root.addView(tv("Generate a one-time code for unlocking child settings. The code is invalidated after first use on the tablet.",15));root.addView(current);Button gen=btn("Generate one-time code");root.addView(gen);gen.setOnClickListener(v->{String who=getSharedPreferences("p",0).getString("parentName","Parent Control");cmdWithCallback("otp_generate",who,resp->{String code=resp.replace("OTP:","").trim();current.setText(code.length()>0?code:"No code returned");addLog("One-time unlock code generated");},err->{current.setText("Failed to generate code");out(err);});});root.addView(log);}
    void showBlockedAppsScreen(){base(tr(R.string.menu_blocked_apps));currentScreen="blocked_apps";String role=getSharedPreferences("p",0).getString("role","");if("child".equals(role)){root.addView(tv(tr(R.string.apps_blocked_on_this_device),16));LinearLayout list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,0,1));renderLocalBlockedAppsList(list);Button refresh=btn(tr(R.string.refresh));root.addView(refresh);refresh.setOnClickListener(v->renderLocalBlockedAppsList(list));return;}root.addView(tv(tr(R.string.blocked_apps_help),14));LinearLayout list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,0,1));LinearLayout actions=new LinearLayout(this);actions.setOrientation(LinearLayout.HORIZONTAL);Button add=btn(tr(R.string.add_app));Button refresh=btn(tr(R.string.refresh));actions.addView(add,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));actions.addView(refresh,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));root.addView(actions);add.setOnClickListener(v->showAddBlockedAppDialog(list));refresh.setOnClickListener(v->loadBlockedAppsList(list));refresh.performClick();root.addView(log);}

    void renderLocalBlockedAppsList(LinearLayout list){list.removeAllViews();Map<String,?> all=getSharedPreferences("rules",0).getAll();long now=System.currentTimeMillis();int count=0;for(String k:all.keySet()){if(!k.startsWith("blocked_until_"))continue;long until=0;try{until=((Number)all.get(k)).longValue();}catch(Exception ignored){}if(until<=now)continue;String pkg=k.substring("blocked_until_".length());LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);TextView name=tv(friendlyAppName(pkg)+"\nuntil "+new java.text.SimpleDateFormat("HH:mm",java.util.Locale.US).format(new java.util.Date(until)),14);Button remove=btn(tr(R.string.remove));row.addView(name,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));row.addView(remove);list.addView(row);remove.setOnClickListener(v->{getSharedPreferences("rules",0).edit().remove("blocked_until_"+pkg).apply();addLog("Activity","Info","Blocked app removed locally",friendlyAppName(pkg));renderLocalBlockedAppsList(list);});count++;}if(count==0)list.addView(tv(tr(R.string.no_blocked_apps),15));}

    String friendlyAppName(String pkg){try{PackageManager pm=getPackageManager();return String.valueOf(pm.getApplicationInfo(pkg,0).loadLabel(pm));}catch(Exception e){return pkg;}}

    String blockedAppsSummary(String resp){ArrayList<BlockedAppEntry> apps=BlockedAppEntry.parseList(resp);return "Blocked apps: "+apps.size()+"    View ›";}
    void updateUsageViews(String resp,TextView screen,TextView apps){long total=0;String[] lines=resp.split("\\n");StringBuilder top=new StringBuilder("Most active apps:\n");int n=0;SharedPreferences.Editor ed=getSharedPreferences("p",0).edit();for(String line:lines){if(line.startsWith("VERSION:")){ed.putString("remoteVersion",line.substring(8).trim());continue;}if(line.startsWith("PROTOCOL:")){ed.putString("remoteProtocol",line.substring(9).trim());continue;}if(line.startsWith("CAPABILITIES:")){ed.putString("remoteCapabilities",line.substring(13).trim());continue;}if(line.startsWith("PERMISSIONS:")){ed.putString("remotePermissions",line.substring(12).trim());continue;}if(line.startsWith("DND:")){ed.putString("remoteDnd",line.substring(4).trim());continue;}if(line.startsWith("BATTERY:")){try{ed.putInt("remoteBattery",Integer.parseInt(line.substring(8).trim()));}catch(Exception ignored){}continue;}if(line.startsWith("CHARGING:")){ed.putBoolean("remoteCharging",Boolean.parseBoolean(line.substring(9).trim()));continue;}if(line.startsWith("WIFI_BARS:")){try{ed.putInt("remoteWifiBars",Integer.parseInt(line.substring(10).trim()));}catch(Exception ignored){}continue;}if(line.startsWith("CURRENT_APP:")){ed.putString("lastCurrentApp",line.substring(12).trim());continue;}if(line.startsWith("CHILD_LANGUAGE:")){ed.putString("childLanguage",line.substring(15).trim());continue;}if(line.startsWith("CHILD_REMOVAL_REQUESTED:")){String val=line.substring(24).trim();ed.putBoolean("childRemovalRequested",Boolean.parseBoolean(val));continue;}if(line.startsWith("ASK_PARENT_REQUESTED:")){String val=line.substring(21).trim();ed.putBoolean("childUnlockRequestPending",Boolean.parseBoolean(val));continue;}if(line.startsWith("CHILD_REMOVAL_METHOD:")){ed.putString("childRemovalMethod",line.substring(21).trim());continue;}if(line.startsWith("ASK_PARENT_REASON:")){ed.putString("childUnlockRequestReason",line.substring(18).trim());continue;}if(line.startsWith("ASK_PARENT_AT:")){try{ed.putLong("childUnlockRequestAt",Long.parseLong(line.substring(14).trim()));}catch(Exception ignored){}continue;}if(line.startsWith("ASK_PARENT_SNOOZE_UNTIL:")){try{ed.putLong("childUnlockSnoozeUntil",Long.parseLong(line.substring(24).trim()));}catch(Exception ignored){}continue;}if(!line.contains(": ")||!line.endsWith(" min"))continue;try{long mins=Long.parseLong(line.substring(line.indexOf(": ")+2,line.indexOf(" min")).trim());total+=mins;if(n<3){top.append(n+1).append(". ").append(line).append("\n");n++;}}catch(Exception ignored){}}ed.putLong("lastStatusMs",System.currentTimeMillis()).putLong("todayMinutes",total).putBoolean("childDeviceRemoved",false).putBoolean("pairingMismatch",false).remove("pairingMismatchMessage").apply();if(getSharedPreferences("p",0).getBoolean("childRemovalRequested",false)){getSharedPreferences("p",0).edit().putBoolean("childRemovalPending",true).apply();String m=getSharedPreferences("p",0).getString("childRemovalMethod","child request");addLog("Security","Warning","Child requested parental-control removal","Authorised by: "+m);tryRemoveChildDeviceOnline();return;}if(getSharedPreferences("p",0).getBoolean("childUnlockRequestPending",false)){SharedPreferences pp=getSharedPreferences("p",0);String reason=pp.getString("childUnlockRequestReason","limitation");long askAt=pp.getLong("childUnlockRequestAt",System.currentTimeMillis());long alertedAt=pp.getLong("lastParentUnlockAlertAt",0);if(askAt<=0)askAt=System.currentTimeMillis();if(askAt!=alertedAt){pp.edit().putLong("lastParentUnlockAlertAt",askAt).apply();addLog("Security","Warning","Child asked parent to unlock",reason);showParentAlertNotification("Unlock request",reason);}}screen.setText(String.format(Locale.US,"Today\n%02d:%02d",total/60,total%60));if(apps!=null){while(n<3){top.append(n+1).append(". --\n");n++;}apps.setText(top.toString());}}

    void startDiscoveryListener(){if(discoveryListenThread!=null&&discoveryListenThread.isAlive())return;discoveryListenThread=new Thread(()->{try{DatagramSocket ds=new DatagramSocket(DISCOVERY_PORT);byte[] buf=new byte[512];while(true){DatagramPacket p=new DatagramPacket(buf,buf.length);ds.receive(p);String msg=new String(p.getData(),0,p.getLength(),StandardCharsets.UTF_8);String[] parts=msg.split("\\|");if(parts.length>=4&&parts[0].equals("FLITE")&&parts[3].equals(pairingId())){String ip=p.getAddress().getHostAddress();if(!ip.equals(childIp)){childIp=ip;new SavedConnection(this).saveChildIp(childIp);out("Child rediscovered at "+childIp);}}}}catch(Exception ignored){}});discoveryListenThread.start();}
    String pairingId(){return CryptoUtils.pairingId(key);}
    interface Ok{void call(String s);} interface Err{void call(String s);} void cmd(String type,String value){cmdWithCallback(type,value,resp->{out(resp);},err->{out(err);});}
    void recordCommandStatus(String id,String command,String status,String details,String value){SharedPreferences p=getSharedPreferences("p",0);String safe=(details==null?"":details.replace("\n"," ").replace("|","/"));String safeValue=(value==null?"":value.replace("\n"," ").replace("|","/"));String line=System.currentTimeMillis()+"|"+id+"|"+command+"|"+status+"|"+safe+"|"+safeValue;String hist=p.getString("commandHistory","");String[] old=hist.length()==0?new String[0]:hist.split("\n");StringBuilder next=new StringBuilder(line);int kept=0;for(String row:old){if(row.trim().length()==0)continue;String[] parts=row.split("\\|",-1);if(parts.length>1&&parts[1].equals(id))continue;if(kept++>=24)break;next.append("\n").append(row);}p.edit().putString("lastCommandStatus",prettyCommandName(command)+": "+status).putString("commandHistory",next.toString()).putString("commandLifecycleHistory",next.toString()).apply();}
    void cmdWithCallback(String type,String value,Ok ok,Err err){String commandLabel=type==null?"command":type;String commandId=java.util.UUID.randomUUID().toString();String commandValue=value==null?"":value;boolean quiet=commandLabel.equals("usage")||commandLabel.equals("blocked_apps")||commandLabel.equals("hello")||commandLabel.equals("chat_status");if(!quiet){out("Sending: "+commandLabel);recordCommandStatus(commandId,commandLabel,"Sending",commandValue,commandValue);}new CommandClient(this).send(childIp,key,type,value,resp->{if(!quiet){out("Delivered: "+commandLabel);recordCommandStatus(commandId,commandLabel,"Delivered",resp,commandValue);}if("disable_use".equals(commandLabel))setLocalLockState(true);if("enable_use".equals(commandLabel)){setLocalLockState(false);setLocalTimeoutState(false);}if("lock_timeout".equals(commandLabel))setLocalTimeoutState(true);if("stop_timeout".equals(commandLabel))setLocalTimeoutState(false);if("remove_all_limitations".equals(commandLabel)){setLocalLockState(false);setLocalTimeoutState(false);}ok.call(resp);},e->{String low=e==null?"":e.toLowerCase(java.util.Locale.US);if(low.contains("handshake")||low.contains("decrypt")||low.contains("auth")||low.contains("bad tag")){getSharedPreferences("p",0).edit().putBoolean("pairingMismatch",true).putString("pairingMismatchReason",e).apply();try{startService(new Intent(this,ParentMonitorService.class));}catch(Exception ignored){}}if(!quiet){out("Failed: "+commandLabel);recordCommandStatus(commandId,commandLabel,"Failed",e,commandValue);}err.call(e);});}

    static String currentPairCode(byte[] k){return CryptoUtils.currentPairCode(k);}
    byte[] getOrCreateKey(){String saved=getSharedPreferences("p",0).getString("key",null);if(saved!=null)return Base64.getDecoder().decode(saved);byte[] b=new byte[32];new SecureRandom().nextBytes(b);getSharedPreferences("p",0).edit().putString("key",Base64.getEncoder().encodeToString(b)).apply();return b;}
    String getIp(){try{WifiManager wm=(WifiManager)getApplicationContext().getSystemService(WIFI_SERVICE);return Formatter.formatIpAddress(wm.getConnectionInfo().getIpAddress());}catch(Exception e){return "0.0.0.0";}}
    Bitmap qrBitmap(String text,int size){try{BitMatrix m=new MultiFormatWriter().encode(text,BarcodeFormat.QR_CODE,size,size);Bitmap bmp=Bitmap.createBitmap(size,size,Bitmap.Config.RGB_565);for(int x=0;x<size;x++)for(int y=0;y<size;y++)bmp.setPixel(x,y,m.get(x,y)?Color.BLACK:Color.WHITE);return bmp;}catch(Exception e){Bitmap b=Bitmap.createBitmap(10,10,Bitmap.Config.RGB_565);b.eraseColor(Color.LTGRAY);return b;}}
    void listenLogs(){try{if(br!=null)unregisterReceiver(br);}catch(Exception ignored){}br=new BroadcastReceiver(){public void onReceive(Context c,Intent i){out(i.getStringExtra("msg"));}};if(Build.VERSION.SDK_INT>=33)registerReceiver(br,new IntentFilter("com.enigma.familylinklite.LOG"),RECEIVER_NOT_EXPORTED);else registerReceiver(br,new IntentFilter("com.enigma.familylinklite.LOG"));}

    void ensureParentNotificationChannels(){try{if(Build.VERSION.SDK_INT>=26){NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);android.net.Uri sound=android.provider.Settings.System.DEFAULT_NOTIFICATION_URI;NotificationChannel alerts=new NotificationChannel("parent_alerts_v2","Parental-Link urgent parent alerts",NotificationManager.IMPORTANCE_HIGH);alerts.setDescription("Noisy popup alerts for child unlock requests and urgent parent actions");alerts.enableVibration(true);alerts.setSound(sound,new android.media.AudioAttributes.Builder().setUsage(android.media.AudioAttributes.USAGE_NOTIFICATION).setContentType(android.media.AudioAttributes.CONTENT_TYPE_SONIFICATION).build());nm.createNotificationChannel(alerts);NotificationChannel commands=new NotificationChannel("parent_command_status","Parental-Link command status",NotificationManager.IMPORTANCE_DEFAULT);commands.setDescription("Status updates for commands sent to the child device");commands.enableVibration(false);nm.createNotificationChannel(commands);}}catch(Exception ignored){}}
    boolean parentAlertsAllowed(){if(Build.VERSION.SDK_INT<33)return true;return checkSelfPermission(Manifest.permission.POST_NOTIFICATIONS)==PackageManager.PERMISSION_GRANTED;}
    void openAppNotificationSettings(){try{Intent i=new Intent(Settings.ACTION_APP_NOTIFICATION_SETTINGS).putExtra(Settings.EXTRA_APP_PACKAGE,getPackageName());startActivity(i);}catch(Exception e){startActivity(new Intent(Settings.ACTION_APPLICATION_DETAILS_SETTINGS,Uri.parse("package:"+getPackageName())));}}
    void showParentAlertNotification(String title,String text){try{NotificationManager nm=(NotificationManager)getSystemService(NOTIFICATION_SERVICE);String ch="parent_alerts_v2";android.net.Uri sound=android.provider.Settings.System.DEFAULT_NOTIFICATION_URI;if(Build.VERSION.SDK_INT>=26){NotificationChannel c=new NotificationChannel(ch,"Parental-Link parent alerts",NotificationManager.IMPORTANCE_HIGH);c.setDescription("Urgent parent alerts from the child device");c.enableVibration(true);c.setSound(sound,new android.media.AudioAttributes.Builder().setUsage(android.media.AudioAttributes.USAGE_NOTIFICATION).setContentType(android.media.AudioAttributes.CONTENT_TYPE_SONIFICATION).build());nm.createNotificationChannel(c);}Intent i=new Intent(this,MainActivity.class).putExtra("open","unlock_request");PendingIntent pi=PendingIntent.getActivity(this,22,i,PendingIntent.FLAG_UPDATE_CURRENT|PendingIntent.FLAG_IMMUTABLE);Intent allow=new Intent(this,ParentActionReceiver.class).setAction("com.enigma.familylinklite.ALLOW_CHILD_UNLOCK");PendingIntent allowPi=PendingIntent.getBroadcast(this,23,allow,PendingIntent.FLAG_UPDATE_CURRENT|PendingIntent.FLAG_IMMUTABLE);Intent snooze=new Intent(this,ParentActionReceiver.class).setAction("com.enigma.familylinklite.SNOOZE_CHILD_REQUEST");PendingIntent snoozePi=PendingIntent.getBroadcast(this,24,snooze,PendingIntent.FLAG_UPDATE_CURRENT|PendingIntent.FLAG_IMMUTABLE);Notification.Builder b=Build.VERSION.SDK_INT>=26?new Notification.Builder(this,ch):new Notification.Builder(this);b.setContentTitle(title).setContentText(text).setStyle(new Notification.BigTextStyle().bigText(text)).setSmallIcon(android.R.drawable.ic_dialog_alert).setContentIntent(pi).setAutoCancel(true).setPriority(Notification.PRIORITY_HIGH).setDefaults(Notification.DEFAULT_SOUND|Notification.DEFAULT_VIBRATE).addAction(android.R.drawable.ic_menu_upload,"Allow",allowPi).addAction(android.R.drawable.ic_menu_recent_history,"Snooze",snoozePi);nm.notify(22,b.build());}catch(Exception ignored){}}
    void out(String s){runOnUiThread(()->{if(log!=null)log.setText(s+"\n\n"+log.getText());});} void toast(String s){Toast.makeText(this,s,Toast.LENGTH_SHORT).show();}
